import pickle
import io


class RestrictedUnpickler(pickle.Unpickler):
    """A restricted unpickler that only allows safe built-in types."""
    SAFE_TYPES = {
        'builtins': ['int', 'float', 'bool', 'str', 'bytes', 'list', 'dict', 'tuple', 'set', 'frozenset']
    }

    def find_class(self, module, name):
        # Only allow classes from builtins and only if explicitly listed as safe
        if module == 'builtins' and name in self.SAFE_TYPES.get('builtins', []):
            return getattr(__import__(module), name)
        raise pickle.UnpicklingError(
            f"Global '{module}.{name}' is forbidden"
        )


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if isinstance(pickled, bytes):
        return RestrictedUnpickler(io.BytesIO(pickled)).load()
    elif isinstance(pickled, str):
        return RestrictedUnpickler(io.BytesIO(pickled.encode('utf-8'))).load()
